package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.ast.visitor.ModifierVisitor;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        Path sourcePath = Paths.get(sourceDirectory);

        try {
            // Process all Java files in the directory
            Files.walk(sourcePath)
                .filter(path -> path.toString().endsWith(".java"))
                .forEach(Main::processFile);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static void processFile(Path filePath) {
        try {
            CompilationUnit cu = StaticJavaParser.parse(filePath.toFile());

            // Apply transformations
            new JasyptFixVisitor().visit(cu, null);

            // Save changes back to file
            cu.save(filePath.toFile());
        } catch (Exception e) {
            System.err.println("Error processing file: " + filePath);
            e.printStackTrace();
        }
    }

    /**
     * Visitor that fixes Jasypt API breaking changes
     */
    private static class JasyptFixVisitor extends VoidVisitorAdapter<Void> {

        @Override
        public void visit(ImportDeclaration importDecl, Void arg) {
            super.visit(importDecl, arg);

            // Replace old Jasypt security imports with Spring security equivalents
            String importName = importDecl.getNameAsString();

            if (importName.equals("org.jasypt.spring.security.PasswordEncoder")) {
                importDecl.setname(new Name("org.springframework.security.crypto.password.PasswordEncoder"));
            } else if (importName.equals("org.jasypt.spring.security.PBEPasswordEncoder")) {
                importDecl.setname(new Name("org.springframework.security.crypto.password.PasswordEncoder"));
            } else if (importName.equals("org.acegisecurity.providers.encoding.PasswordEncoder")) {
                importDecl.setname(new Name("org.springframework.security.crypto.password.PasswordEncoder"));
            }
        }

        @Override
        public void visit(ObjectCreationExpr objectCreation, Void arg) {
            super.visit(objectCreation, arg);

            // Replace old PasswordEncoder instantiation
            if (objectCreation.getType().getNameAsString().equals("PasswordEncoder")) {
                // Check if it's the old Jasypt PasswordEncoder class
                if (objectCreation.getArguments().isEmpty()) {
                    // This is likely creating an old Jasypt PasswordEncoder
                    // Replace with Spring PasswordEncoder
                    objectCreation.setType(new ClassOrInterfaceType("org.springframework.security.crypto.password.PasswordEncoder"));
                }
            }

            // Replace old PBEPasswordEncoder instantiation
            if (objectCreation.getType().getNameAsString().equals("PBEPasswordEncoder")) {
                // Replace with Spring PasswordEncoder
                objectCreation.setType(new ClassOrInterfaceType("org.springframework.security.crypto.password.PasswordEncoder"));
            }
        }
    }
}

